const test = require("node:test");
const assert = require("node:assert");
const { run } = require("../src/cli.js");

test("end-to-end: app -> core slugify/titleCase/clamp", () => {
  assert.strictEqual(run(["--name", "grace hopper", "--score", "150"]), "Grace Hopper scored 100");
  assert.strictEqual(run(["--name", "ada_lovelace", "--score", "7"]), "Ada_lovelace scored 7");
});
